
import { getAllLawyers } from "../services/lawyersService";
import { LawyerResponse } from "../models/lawyersModel";
import { Lawyer } from "../models/lawyersModel";
import SearchFilters from "./SearchFilters";
import LawyerList from "./LawyerList";

interface Props {
  searchParams: {
    search?: string;
    category?: string;
    specialization?: string;
    location?: string;
    minExp?: string;
  };
}

export default async function Lawyers({ searchParams }: Props) {
  const res: LawyerResponse = await getAllLawyers();

  if (res.error) {
    throw new Error(res.message);
  }

  const lawyers: Lawyer[] = res.data.data;

  // 🔥 SERVER-SIDE FILTERING LOGIC
  const filteredLawyers = lawyers.filter((lawyer) => {
    // 🔎 Name / keyword search
    const search = searchParams.search?.toLowerCase();
    const matchesSearch =
      !search ||
      lawyer.full_name.toLowerCase().includes(search) ||
      lawyer.username.toLowerCase().includes(search) ||
      lawyer.bio?.toLowerCase().includes(search);

    // 🏷 Category (string | string[])
    const matchesCategory =
      !searchParams.category ||
      searchParams.category === "All" ||
      (Array.isArray(lawyer.category)
        ? lawyer.category.includes(searchParams.category)
        : lawyer.category === searchParams.category);

    // 🎯 Specialization (string | string[])
    const matchesSpecialization =
      !searchParams.specialization ||
      searchParams.specialization === "All" ||
      (Array.isArray(lawyer.specilization)
        ? lawyer.specilization.includes(searchParams.specialization)
        : lawyer.specilization === searchParams.specialization);

    // 📍 Location
    const matchesLocation =
      !searchParams.location ||
      searchParams.location === "All" ||
      lawyer.location === searchParams.location;

    // 🎓 Experience
    const matchesExperience =
      !searchParams.minExp ||
      lawyer.experience >= Number(searchParams.minExp);

    return (
      matchesSearch &&
      matchesCategory &&
      matchesSpecialization &&
      matchesLocation &&
      matchesExperience
    );
  });

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-gradient-to-r from-blue-900 to-blue-700 text-white py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center">
            <h1 className="text-4xl md:text-5xl font-bold mb-4">
              Find Expert Lawyers
            </h1>
            <p className="text-xl text-blue-100 max-w-3xl mx-auto">
              Connect with qualified legal professionals for online
              consultations and expert advice
            </p>
          </div>
        </div>
      </div>
      {/* Search and Filter Section */}
      <div className="bg-white shadow-sm ">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex flex-col lg:flex-row gap-4 items-center">
            <SearchFilters />
          </div>
        </div>
      </div>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <LawyerList lawyers={filteredLawyers} />
      </div>
    </div>
  );
}

